def erase_overlap_intervals(intervals):
    if not intervals:
        return 0
    ordered = sorted(intervals, key=lambda iv: iv[1])
    kept = 1
    last_end = ordered[0][1]
    for start, end in ordered[1:]:
        if start >= last_end:
            kept += 1
            last_end = end
    return len(intervals) - kept
